     4→using System.Text;
     5→using Microsoft.EntityFrameworkCore.Internal;
     6→using Microsoft.EntityFrameworkCore.Metadata.Internal;
     7→
     8→namespace Microsoft.EntityFrameworkCore.Migrations.Design;
     9→
    10→/// <summary>
    11→///     Used to generate C# code for creating an <see cref="IModel" />.
    12→/// </summary>
    13→/// <remarks>
    14→///     See <see href="https://aka.ms/efcore-docs-migrations">Database migrations</see>, and
    15→///     <see href="https://aka.ms/efcore-docs-design-time-services">EF Core design-time services</see> for more information and examples.
    16→/// </remarks>
    17→public class CSharpSnapshotGenerator : ICSharpSnapshotGenerator
    18→{
    19→    private static readonly MethodInfo HasAnnotationMethodInfo
    20→        = typeof(ModelBuilder).GetRuntimeMethod(
    21→            nameof(ModelBuilder.HasAnnotation),
    22→            [typeof(string), typeof(string)])!;
    23→
    24→    private static readonly MethodInfo HasPropertyAnnotationMethodInfo
    25→        = typeof(ComplexPropertyBuilder).GetRuntimeMethod(
    26→            nameof(ComplexPropertyBuilder.HasPropertyAnnotation),
    27→            [typeof(string), typeof(string)])!;
    28→
    29→    private static readonly MethodInfo HasTypeAnnotationMethodInfo
    30→        = typeof(ComplexPropertyBuilder).GetRuntimeMethod(
    31→            nameof(ComplexPropertyBuilder.HasTypeAnnotation),
    32→            [typeof(string), typeof(string)])!;
    33→
    34→    /// <summary>
    35→    ///     Initializes a new instance of the <see cref="CSharpSnapshotGenerator" /> class.
    36→    /// </summary>
    37→    /// <param name="dependencies">The dependencies.</param>
    38→    public CSharpSnapshotGenerator(CSharpSnapshotGeneratorDependencies dependencies)
    39→        => Dependencies = dependencies;
    40→
    41→    /// <summary>
    42→    ///     Dependencies for this service.
    43→    /// </summary>
    44→    protected virtual CSharpSnapshotGeneratorDependencies Dependencies { get; }
    45→
    46→    private ICSharpHelper Code
    47→        => Dependencies.CSharpHelper;
    48→
    49→    /// <summary>
    50→    ///     Generates code for creating an <see cref="IModel" />.
    51→    /// </summary>
    52→    /// <param name="modelBuilderName">The <see cref="ModelBuilder" /> variable name.</param>
    53→    /// <param name="model">The model.</param>
    54→    /// <param name="stringBuilder">The builder code is added to.</param>
    55→    public virtual void Generate(string modelBuilderName, IModel model, IndentedStringBuilder stringBuilder)
    56→    {
    57→        var annotations = Dependencies.AnnotationCodeGenerator
    58→            .FilterIgnoredAnnotations(model.GetAnnotations())
    59→            .ToDictionary(a => a.Name, a => a);
    60→
    61→        if (model.GetProductVersion() is { } productVersion)
    62→        {
    63→            annotations[CoreAnnotationNames.ProductVersion] = new Annotation(CoreAnnotationNames.ProductVersion, productVersion);
    64→        }
    65→
    66→        GenerateAnnotations(modelBuilderName, model, stringBuilder, annotations, inChainedCall: false, leadingNewline: false);
    67→
    68→        foreach (var sequence in model.GetSequences())
    69→        {
    70→            GenerateSequence(modelBuilderName, sequence, stringBuilder);
    71→        }
    72→
    73→        GenerateEntityTypes(modelBuilderName, model.GetEntityTypesInHierarchicalOrder(), stringBuilder);
    74→    }
    75→
    76→    /// <summary>
    77→    ///     Generates code for <see cref="IEntityType" /> objects.
    78→    /// </summary>
    79→    /// <param name="modelBuilderName">The name of the builder variable.</param>
    80→    /// <param name="entityTypes">The entity types.</param>
    81→    /// <param name="stringBuilder">The builder code is added to.</param>
    82→    protected virtual void GenerateEntityTypes(
    83→        string modelBuilderName,
    84→        IEnumerable<IEntityType> entityTypes,
    85→        IndentedStringBuilder stringBuilder)
    86→    {
    87→        var nonOwnedTypes = entityTypes.Where(e => e.FindOwnership() == null).ToList();
    88→        foreach (var entityType in nonOwnedTypes)
    89→        {
    90→            stringBuilder.AppendLine();
    91→
    92→            GenerateEntityType(modelBuilderName, entityType, stringBuilder);
    93→        }
    94→
    95→        foreach (var entityType in nonOwnedTypes.Where(e => e.GetDeclaredForeignKeys().Any()
    96→                     || e.GetDeclaredReferencingForeignKeys().Any(fk => fk.IsOwnership)))
    97→        {
    98→            stringBuilder.AppendLine();
    99→
   100→            GenerateEntityTypeRelationships(modelBuilderName, entityType, stringBuilder);
   101→        }
   102→
   103→        foreach (var entityType in nonOwnedTypes.Where(e
   104→                     => e.GetDeclaredNavigations().Any(n => n is { IsOnDependent: false, ForeignKey.IsOwnership: false })))
   105→        {
   106→            stringBuilder.AppendLine();
   107→
   108→            GenerateEntityTypeNavigations(modelBuilderName, entityType, stringBuilder);
   109→        }
   110→    }
   111→
   112→    /// <summary>
   113→    ///     Generates code for an <see cref="IEntityType" />.
   114→    /// </summary>
   115→    /// <param name="builderName">The name of the builder variable.</param>
   116→    /// <param name="entityType">The entity type.</param>
   117→    /// <param name="stringBuilder">The builder code is added to.</param>
   118→    protected virtual void GenerateEntityType(
   119→        string builderName,
   120→        IEntityType entityType,
   121→        IndentedStringBuilder stringBuilder)
   122→    {
   123→        var ownership = entityType.FindOwnership();
   124→        var ownerNavigation = ownership?.PrincipalToDependent!.Name;
   125→        var entityTypeName = entityType.Name;
   126→        if (ownerNavigation != null
   127→            && entityType.HasSharedClrType)
   128→        {
   129→            if (entityTypeName == ownership!.PrincipalEntityType.GetOwnedName(entityType.ClrType.ShortDisplayName(), ownerNavigation))
   130→            {
   131→                entityTypeName = entityType.ClrType.DisplayName();
   132→            }
   133→            else if (entityTypeName == ownership.PrincipalEntityType.GetOwnedName(entityType.ShortName(), ownerNavigation))
   134→            {
   135→                entityTypeName = entityType.ShortName();
   136→            }
   137→        }
   138→
   139→        var entityTypeBuilderName = GenerateNestedBuilderName(builderName);
   140→
   141→        stringBuilder
   142→            .Append(builderName)
   143→            .Append(
   144→                ownerNavigation != null
   145→                    ? ownership!.IsUnique ? ".OwnsOne(" : ".OwnsMany("
   146→                    : ".Entity(")
   147→            .Append(Code.Literal(entityTypeName));
   148→
   149→        if (ownerNavigation != null)
   150→        {
   151→            stringBuilder
   152→                .Append(", ")
   153→                .Append(Code.Literal(ownerNavigation));
   154→        }
   155→
   156→        stringBuilder
   157→            .Append(", ")
   158→            .Append(entityTypeBuilderName)
   159→            .AppendLine(" =>");
   160→
   161→        using (stringBuilder.Indent())
   162→        {
   163→            stringBuilder.Append("{");
   164→
   165→            using (stringBuilder.Indent())
   166→            {
   167→                GenerateBaseType(entityTypeBuilderName, entityType.BaseType, stringBuilder);
   168→
   169→                GenerateProperties(entityTypeBuilderName, entityType.GetDeclaredProperties(), stringBuilder);
   170→
   171→                GenerateComplexProperties(entityTypeBuilderName, entityType.GetDeclaredComplexProperties(), stringBuilder);
   172
   173→                GenerateKeys(
   174→                    entityTypeBuilderName,
   175→                    entityType.GetDeclaredKeys(),
   176→                    entityType.BaseType == null ? entityType.FindPrimaryKey() : null,
   177→                    stringBuilder);
   178→
   179→                GenerateIndexes(entityTypeBuilderName, entityType.GetDeclaredIndexes(), stringBuilder);
   180→
   181→                GenerateEntityTypeAnnotations(entityTypeBuilderName, entityType, stringBuilder);
   182→
   183→                if (ownerNavigation != null)
   184→                {
   185→                    GenerateRelationships(entityTypeBuilderName, entityType, stringBuilder);
   186→
   187→                    GenerateNavigations(
   188→                        entityTypeBuilderName, entityType.GetDeclaredNavigations()
   189→                            .Where(n => !n.IsOnDependent && !n.ForeignKey.IsOwnership), stringBuilder);
   190→                }
   191→
   192→                GenerateData(
   193→                    entityTypeBuilderName, entityType.GetProperties(), entityType.GetSeedData(providerValues: true), stringBuilder);
   194→            }
   195→
   196→            stringBuilder
   197→                .AppendLine("});");
   198→        }
   199→    }
   200→
   201→    /// <summary>
   202→    ///     Generates code for owned entity types.
   203→    /// </summary>
   204→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
   205→    /// <param name="ownerships">The foreign keys identifying each entity type.</param>
   206→    /// <param name="stringBuilder">The builder code is added to.</param>
   207→    protected virtual void GenerateOwnedTypes(
   208→        string entityTypeBuilderName,
   209→        IEnumerable<IForeignKey> ownerships,
   210→        IndentedStringBuilder stringBuilder)
   211→    {
   212→        foreach (var ownership in ownerships)
   213→        {
   214→            stringBuilder.AppendLine();
   215→
   216→            GenerateOwnedType(entityTypeBuilderName, ownership, stringBuilder);
   217→        }
   218→    }
   219→
   220→    /// <summary>
   221→    ///     Generates code for an owned entity types.
   222→    /// </summary>
   223→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
   224→    /// <param name="ownership">The foreign key identifying the entity type.</param>
   225→    /// <param name="stringBuilder">The builder code is added to.</param>
   226→    protected virtual void GenerateOwnedType(
   227→        string entityTypeBuilderName,
   228→        IForeignKey ownership,
   229→        IndentedStringBuilder stringBuilder)
   230→        => GenerateEntityType(entityTypeBuilderName, ownership.DeclaringEntityType, stringBuilder);
   231→
   232→    /// <summary>
   233→    ///     Generates code for the relationships of an <see cref="IEntityType" />.
   234→    /// </summary>
   235→    /// <param name="modelBuilderName">The name of the builder variable.</param>
   236→    /// <param name="entityType">The entity type.</param>
   237→    /// <param name="stringBuilder">The builder code is added to.</param>
   238→    protected virtual void GenerateEntityTypeRelationships(
   239→        string modelBuilderName,
   240→        IEntityType entityType,
   241→        IndentedStringBuilder stringBuilder)
   242→    {
   243→        stringBuilder
   244→            .Append(modelBuilderName)
   245→            .Append(".Entity(")
   246→            .Append(Code.Literal(entityType.Name))
   247→            .AppendLine(", b =>");
   248→
   249→        using (stringBuilder.Indent())
   250→        {
   251→            stringBuilder.Append("{");
   252→
   253→            using (stringBuilder.Indent())
   254→            {
   255→                GenerateRelationships("b", entityType, stringBuilder);
   256→            }
   257→
   258→            stringBuilder.AppendLine("});");
   259→        }
   260→    }
   261→
   262→    /// <summary>
   263→    ///     Generates code for the relationships of an <see cref="IEntityType" />.
   264→    /// </summary>
   265→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
   266→    /// <param name="entityType">The entity type.</param>
   267→    /// <param name="stringBuilder">The builder code is added to.</param>
   268→    protected virtual void GenerateRelationships(
   269→        string entityTypeBuilderName,
   270→        IEntityType entityType,
   271→        IndentedStringBuilder stringBuilder)
   272→    {
   273→        GenerateForeignKeys(entityTypeBuilderName, entityType.GetDeclaredForeignKeys(), stringBuilder);
   274→
   275→        GenerateOwnedTypes(
   276→            entityTypeBuilderName, entityType.GetDeclaredReferencingForeignKeys().Where(fk => fk.IsOwnership), stringBuilder);
   277→
   278→        GenerateNavigations(
   279→            entityTypeBuilderName, entityType.GetDeclaredNavigations()
   280→                .Where(n => n.IsOnDependent || (!n.IsOnDependent && n.ForeignKey.IsOwnership)), stringBuilder);
   281→    }
   282→
   283→    /// <summary>
   284→    ///     Generates code for the base type of an <see cref="IEntityType" />.
   285→    /// </summary>
   286→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
   287→    /// <param name="baseType">The base entity type.</param>
   288→    /// <param name="stringBuilder">The builder code is added to.</param>
   289→    protected virtual void GenerateBaseType(
   290→        string entityTypeBuilderName,
   291→        IEntityType? baseType,
   292→        IndentedStringBuilder stringBuilder)
   293→    {
   294→        if (baseType != null)
   295→        {
   296→            stringBuilder
   297→                .AppendLine()
   298→                .Append(entityTypeBuilderName)
   299→                .Append(".HasBaseType(")
   300→                .Append(Code.Literal(GetFullName(baseType)))
   301→                .AppendLine(");");
   302→        }
   303→    }
   304→
   305→    /// <summary>
   306→    ///     Generates code for an <see cref="ISequence" />.
   307→    /// </summary>
   308→    /// <param name="modelBuilderName">The name of the builder variable.</param>
   309→    /// <param name="sequence">The sequence.</param>
   310→    /// <param name="stringBuilder">The builder code is added to.</param>
   311→    protected virtual void GenerateSequence(
   312→        string modelBuilderName,
   313→        ISequence sequence,
   314→        IndentedStringBuilder stringBuilder)
   315→    {
   316→        var sequenceBuilderNameBuilder = new StringBuilder();
   317→        sequenceBuilderNameBuilder
   318→            .Append(modelBuilderName)
   319→            .Append(".HasSequence");
   320→
   321→        if (sequence.Type != Sequence.DefaultClrType)
   322→        {
   323→            sequenceBuilderNameBuilder
   324→                .Append('<')
   325→                .Append(Code.Reference(sequence.Type))
   326→                .Append('>');
   327→        }
   328→
   329→        sequenceBuilderNameBuilder
   330→            .Append('(')
   331→            .Append(Code.Literal(sequence.Name));
   332→
   333→        if (!string.IsNullOrEmpty(sequence.ModelSchema))
   334→        {
   335→            sequenceBuilderNameBuilder
   336→                .Append(", ")
   337→                .Append(Code.Literal(sequence.ModelSchema));
   338→        }
   339→
   340→        sequenceBuilderNameBuilder.Append(')');
   341→        var sequenceBuilderName = sequenceBuilderNameBuilder.ToString();
   342→
   343→        stringBuilder
   344→            .AppendLine()
   345→            .Append(sequenceBuilderName);
   346→
   347→        // Note that GenerateAnnotations below does the corresponding decrement
   348→        stringBuilder.IncrementIndent();
   349→
   350→        if (sequence.StartValue != Sequence.DefaultStartValue)
   351→        {
   352→            stringBuilder
   353→                .AppendLine()
   354→                .Append(".StartsAt(")
   355→                .Append(Code.Literal(sequence.StartValue))
   356→                .Append(')');
   357→        }
   358→
   359→        if (sequence.IncrementBy != Sequence.DefaultIncrementBy)
   360→        {
   361→            stringBuilder
   362→                .AppendLine()
   363→                .Append(".IncrementsBy(")
   364→                .Append(Code.Literal(sequence.IncrementBy))
   365→                .Append(')');
   366→        }
   367→
   368→        if (sequence.MinValue != Sequence.DefaultMinValue)
   369→        {
   370→            stringBuilder
   371→                .AppendLine()
   372→                .Append(".HasMin(")
   373→                .Append(Code.Literal(sequence.MinValue))
   374→                .Append(")");
   375→        }
   376→
   377→        if (sequence.MaxValue != Sequence.DefaultMaxValue)
   378→        {
   379→            stringBuilder
   380→                .AppendLine()
   381→                .Append(".HasMax(")
   382→                .Append(Code.Literal(sequence.MaxValue))
   383→                .Append(')');
   384→        }
   385→
   386→        if (sequence.IsCyclic != Sequence.DefaultIsCyclic)
   387→        {
   388→            stringBuilder
   389→                .AppendLine()
   390→                .Append(".IsCyclic()");
   391→        }
   392→
   393→        GenerateSequenceAnnotations(sequenceBuilderName, sequence, stringBuilder);
   394→    }
   395→
   396→    /// <summary>
   397→    ///     Generates code for sequence annotations.
   398→    /// </summary>
   399→    /// <param name="sequenceBuilderName">The name of the sequence builder variable.</param>
   400→    /// <param name="sequence">The sequence.</param>
   401→    /// <param name="stringBuilder">The builder code is added to.</param>
   402→    protected virtual void GenerateSequenceAnnotations(
   403→        string sequenceBuilderName,
   404→        ISequence sequence,
   405→        IndentedStringBuilder stringBuilder)
   406→    {
   407→        var annotations = Dependencies.AnnotationCodeGenerator
   408→            .FilterIgnoredAnnotations(sequence.GetAnnotations())
   409→            .ToDictionary(a => a.Name, a => a);
   410→
   411→        GenerateAnnotations(sequenceBuilderName, sequence, stringBuilder, annotations, inChainedCall: true);
   412→    }
   413→
   414→    /// <summary>
   415→    ///     Generates code for <see cref="IProperty" /> objects.
   416→    /// </summary>
   417→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
   418→    /// <param name="properties">The properties.</param>
   419→    /// <param name="stringBuilder">The builder code is added to.</param>
   420→    protected virtual void GenerateProperties(
   421→        string entityTypeBuilderName,
   422→        IEnumerable<IProperty> properties,
   423→        IndentedStringBuilder stringBuilder)
   424→    {
   425→        foreach (var property in properties)
   426→        {
   427→            GenerateProperty(entityTypeBuilderName, property, stringBuilder);
   428→        }
   429→    }
   430→
   431→    /// <summary>
   432→    ///     Generates code for an <see cref="IProperty" />.
   433→    /// </summary>
   434→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
   435→    /// <param name="property">The property.</param>
   436→    /// <param name="stringBuilder">The builder code is added to.</param>
   437→    protected virtual void GenerateProperty(
   438→        string entityTypeBuilderName,
   439→        IProperty property,
   440→        IndentedStringBuilder stringBuilder)
   441→    {
   442→        var clrType = (FindValueConverter(property)?.ProviderClrType ?? property.ClrType)
   443→            .MakeNullable(property.IsNullable);
   444→
   445→        var propertyCall = property.IsPrimitiveCollection ? "PrimitiveCollection" : "Property";
   446→        var propertyBuilderName = $"{entityTypeBuilderName}.{propertyCall}<{Code.Reference(clrType)}>({Code.Literal(property.Name)})";
   447→
   448→        stringBuilder
   449→            .AppendLine()
   450→            .Append(propertyBuilderName);
   451→
   452→        // Note that GenerateAnnotations below does the corresponding decrement
   453→        stringBuilder.IncrementIndent();
   454→
   455→        if (property.IsConcurrencyToken)
   456→        {
   457→            stringBuilder
   458→                .AppendLine()
   459→                .Append(".IsConcurrencyToken()");
   460→        }
   461→
   462→        if (property.IsNullable != (clrType.IsNullableType() && !property.IsPrimaryKey()))
   463→        {
   464→            stringBuilder
   465→                .AppendLine()
   466→                .Append(".IsRequired()");
   467→        }
   468→
   469→        if (property.ValueGenerated != ValueGenerated.Never)
   470→        {
   471→            stringBuilder
   472→                .AppendLine()
   473→                .Append(
   474→                    property.ValueGenerated == ValueGenerated.OnAdd
   475→                        ? ".ValueGeneratedOnAdd()"
   476→                        : property.ValueGenerated == ValueGenerated.OnUpdate
   477→                            ? ".ValueGeneratedOnUpdate()"
   478→                            : property.ValueGenerated == ValueGenerated.OnUpdateSometimes
