   496→    {
   497→        var annotations = Dependencies.AnnotationCodeGenerator
   498→            .FilterIgnoredAnnotations(property.GetAnnotations())
   499→            .ToDictionary(a => a.Name, a => a);
   500→
   501→        GenerateFluentApiForMaxLength(property, stringBuilder);
   502→        GenerateFluentApiForPrecisionAndScale(property, stringBuilder);
   503→        GenerateFluentApiForIsUnicode(property, stringBuilder);
   504→
   505→        if (!annotations.ContainsKey(RelationalAnnotationNames.ColumnType)
   506→            && !property.DeclaringType.IsMappedToJson())
   507→        {
   508→            annotations[RelationalAnnotationNames.ColumnType] = new Annotation(
   509→                RelationalAnnotationNames.ColumnType,
   510→                property.GetColumnType());
   511→        }
   512→
   513→        if (annotations.ContainsKey(RelationalAnnotationNames.DefaultValue)
   514→            && property.TryGetDefaultValue(out var defaultValue)
   515→            && defaultValue != DBNull.Value
   516→            && FindValueConverter(property) is { } valueConverter)
   517→        {
