   519→                RelationalAnnotationNames.DefaultValue,
   520→                valueConverter.ConvertToProvider(defaultValue));
   521→        }
   522→
   523→        if (!annotations.ContainsKey(RelationalAnnotationNames.ColumnName)
   524→            && property.Name != property.GetColumnName())
   525→        {
   526→            annotations[RelationalAnnotationNames.ColumnName] = new Annotation(
   527→                RelationalAnnotationNames.ColumnName,
   528→                property.GetColumnName());
   529→        }
