   632→        var discriminatorProperty = property.ComplexType.FindDiscriminatorProperty();
   633→        if (discriminatorProperty != null)
   634→        {
   635→            stringBuilder
   636→                .AppendLine()
   637→                .Append(propertyBuilderName)
   638→                .Append('.')
   639→                .Append("HasDiscriminator");
   640→
   641→            if (discriminatorProperty.DeclaringType == property.ComplexType
   642→                && discriminatorProperty.Name != "Discriminator")
   643→            {
   644→                var propertyClrType = FindValueConverter(discriminatorProperty)?.ProviderClrType
   645→                        .MakeNullable(discriminatorProperty.IsNullable)
   646→                    ?? discriminatorProperty.ClrType;
   647→                stringBuilder
   648→                    .Append('<')
   649→                    .Append(Code.Reference(propertyClrType))
   650→                    .Append(">(")
   651→                    .Append(Code.Literal(discriminatorProperty.Name))
   652→                    .Append(')');
   653→            }
   654→            else
   655→            {
   656→                stringBuilder
   657→                    .Append("()");
   658→            }
   659→
   660→            var discriminatorValue = property.ComplexType.GetDiscriminatorValue();
   661→            if (discriminatorValue != null)
   662→            {
   663→                var valueConverter = FindValueConverter(discriminatorProperty);
