   685→            .FilterIgnoredAnnotations(property.ComplexType.GetAnnotations())
   686→            .ToDictionary(a => a.Name, a => a);
   687→
   688→        GenerateAnnotations(
   689→            propertyBuilderName, property, stringBuilder, propertyAnnotations,
   690→            inChainedCall: false, hasAnnotationMethodInfo: HasPropertyAnnotationMethodInfo);
   691→
   692→        GenerateAnnotations(
   693→            propertyBuilderName, property.ComplexType, stringBuilder, typeAnnotations,
   694→            inChainedCall: false, hasAnnotationMethodInfo: HasTypeAnnotationMethodInfo);
