   853→    /// <summary>
   854→    ///     Generates code for the annotations on an entity type.
   855→    /// </summary>
   856→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
   857→    /// <param name="entityType">The entity type.</param>
   858→    /// <param name="stringBuilder">The builder code is added to.</param>
   859→    protected virtual void GenerateEntityTypeAnnotations(
   860→        string entityTypeBuilderName,
   861→        IEntityType entityType,
   862→        IndentedStringBuilder stringBuilder)
   863→    {
   864→        IAnnotation? discriminatorPropertyAnnotation = null;
   865→        IAnnotation? discriminatorValueAnnotation = null;
   866→        IAnnotation? discriminatorMappingCompleteAnnotation = null;
   867→
   868→        foreach (var annotation in entityType.GetAnnotations())
   869→        {
   870→            switch (annotation.Name)
   871→            {
   872→                case CoreAnnotationNames.DiscriminatorProperty:
   873→                    discriminatorPropertyAnnotation = annotation;
   874→                    break;
   875→                case CoreAnnotationNames.DiscriminatorValue:
   876→                    discriminatorValueAnnotation = annotation;
   877→                    break;
   878→                case CoreAnnotationNames.DiscriminatorMappingComplete:
   879→                    discriminatorMappingCompleteAnnotation = annotation;
   880→                    break;
   881→            }
   882→        }
   883→
   884→        var annotations = Dependencies.AnnotationCodeGenerator
   885→            .FilterIgnoredAnnotations(entityType.GetAnnotations())
   886→            .ToDictionary(a => a.Name, a => a);
   887→
   888→        GenerateTableMapping(entityTypeBuilderName, entityType, stringBuilder, annotations);
   889→        GenerateSplitTableMapping(entityTypeBuilderName, entityType, stringBuilder);
   890→
   891→        GenerateViewMapping(entityTypeBuilderName, entityType, stringBuilder, annotations);
   892→        GenerateSplitViewMapping(entityTypeBuilderName, entityType, stringBuilder);
   893→
   894→        var functionNameAnnotation = annotations.Find(RelationalAnnotationNames.FunctionName);
   895→        if (functionNameAnnotation != null
   896→            || entityType.BaseType == null)
   897→        {
   898→            var functionName = (string?)functionNameAnnotation?.Value ?? entityType.GetFunctionName();
   899→            if (functionName != null
   900→                || functionNameAnnotation != null)
   901→            {
   902→                stringBuilder
   903→                    .AppendLine()
   904→                    .Append(entityTypeBuilderName)
   905→                    .Append(".ToFunction(")
   906→                    .Append(Code.Literal(functionName))
   907→                    .AppendLine(");");
   908→                if (functionNameAnnotation != null)
   909→                {
   910→                    annotations.Remove(functionNameAnnotation.Name);
   911→                }
   912→            }
   913→        }
   914→
   915→        var sqlQueryAnnotation = annotations.Find(RelationalAnnotationNames.SqlQuery);
   916→        if (sqlQueryAnnotation != null
   917→            || entityType.BaseType == null)
   918→        {
   919→            var sqlQuery = (string?)sqlQueryAnnotation?.Value ?? entityType.GetSqlQuery();
   920→            if (sqlQuery != null
   921→                || sqlQueryAnnotation != null)
   922→            {
   923→                stringBuilder
   924→                    .AppendLine()
   925→                    .Append(entityTypeBuilderName)
   926→                    .Append(".ToSqlQuery(")
   927→                    .Append(Code.Literal(sqlQuery))
   928→                    .AppendLine(");");
   929→                if (sqlQueryAnnotation != null)
   930→                {
   931→                    annotations.Remove(sqlQueryAnnotation.Name);
   932→                }
   933→            }
   934→        }
   935→
   936→        if ((discriminatorPropertyAnnotation?.Value
   937→                ?? discriminatorMappingCompleteAnnotation?.Value
   938→                ?? discriminatorValueAnnotation?.Value)
   939→            != null)
   940→        {
   941→            var discriminatorProperty = entityType.FindDiscriminatorProperty();
   942→            if (discriminatorProperty != null)
   943→            {
   944→                stringBuilder
   945→                    .AppendLine()
   946→                    .Append(entityTypeBuilderName)
   947→                    .Append('.')
   948→                    .Append("HasDiscriminator");
   949→
   950→                if (discriminatorProperty.DeclaringType == entityType
   951→                    && discriminatorProperty.Name != "Discriminator")
   952→                {
   953→                    var propertyClrType = FindValueConverter(discriminatorProperty)?.ProviderClrType
   954→                            .MakeNullable(discriminatorProperty.IsNullable)
   955→                        ?? discriminatorProperty.ClrType;
   956→                    stringBuilder
   957→                        .Append('<')
   958→                        .Append(Code.Reference(propertyClrType))
   959→                        .Append(">(")
   960→                        .Append(Code.Literal(discriminatorProperty.Name))
   961→                        .Append(')');
   962→                }
   963→                else
   964→                {
   965→                    stringBuilder
   966→                        .Append("()");
   967→                }
   968→
   969→                if (discriminatorMappingCompleteAnnotation?.Value != null)
   970→                {
   971→                    var value = (bool)discriminatorMappingCompleteAnnotation.Value;
   972→
   973→                    stringBuilder
   974→                        .Append('.')
   975→                        .Append("IsComplete")
   976→                        .Append('(')
   977→                        .Append(Code.Literal(value))
   978→                        .Append(')');
   979→                }
   980→
   981→                if (discriminatorValueAnnotation?.Value != null)
   982→                {
   983→                    var value = discriminatorValueAnnotation.Value;
   984→                    var valueConverter = FindValueConverter(discriminatorProperty);
   985→                    if (valueConverter != null)
   986→                    {
   987→                        value = valueConverter.ConvertToProvider(value);
   988→                    }
   989→
   990→                    stringBuilder
   991→                        .Append('.')
   992→                        .Append("HasValue")
   993→                        .Append('(')
   994→                        .Append(Code.UnknownLiteral(value))
   995→                        .Append(')');
   996→                }
   997→
   998→                stringBuilder.AppendLine(";");
   999→            }
  1000→        }
  1001→
  1002→        GenerateAnnotations(entityTypeBuilderName, entityType, stringBuilder, annotations, inChainedCall: false);
  1003→    }
