  1005→    private void GenerateTableMapping(
  1006→        string entityTypeBuilderName,
  1007→        IEntityType entityType,
  1008→        IndentedStringBuilder stringBuilder,
  1009→        Dictionary<string, IAnnotation> annotations)
  1010→    {
  1011→        annotations.TryGetAndRemove(RelationalAnnotationNames.TableName, out IAnnotation? tableNameAnnotation);
  1012→        var table = StoreObjectIdentifier.Create(entityType, StoreObjectType.Table);
  1013→        var tableName = (string?)tableNameAnnotation?.Value ?? table?.Name;
  1014→
  1015→        annotations.TryGetAndRemove(RelationalAnnotationNames.Schema, out IAnnotation? schemaAnnotation);
  1016→        var schema = (string?)schemaAnnotation?.Value ?? table?.Schema;
  1017→
  1018→        annotations.TryGetAndRemove(RelationalAnnotationNames.IsTableExcludedFromMigrations, out IAnnotation? isExcludedAnnotation);
  1019→        var isExcludedFromMigrations = (isExcludedAnnotation?.Value as bool?) == true;
  1020→
  1021→        annotations.TryGetAndRemove(RelationalAnnotationNames.Comment, out IAnnotation? commentAnnotation);
  1022→        var comment = (string?)commentAnnotation?.Value;
  1023→
  1024→        var hasTriggers = entityType.GetDeclaredTriggers().Any(t => t.GetTableName() == tableName! && t.GetTableSchema() == schema);
  1025→        var hasOverrides = table != null
  1026→            && entityType.GetProperties().Select(p => p.FindOverrides(table.Value)).Any(o => o != null);
  1027→
  1028→        var explicitName = tableNameAnnotation != null
  1029→            || entityType.BaseType == null
  1030→            || (entityType.GetMappingStrategy() == RelationalAnnotationNames.TpcMappingStrategy && entityType.IsAbstract())
  1031→            || entityType.BaseType.GetTableName() != tableName
  1032→            || hasOverrides;
  1033→
  1034→        var requiresTableBuilder = isExcludedFromMigrations
  1035→            || comment != null
  1036→            || hasTriggers
  1037→            || hasOverrides
  1038→            || entityType.GetCheckConstraints().Any();
  1039→
  1040→        if (!explicitName
  1041→            && !requiresTableBuilder)
  1042→        {
  1043→            return;
  1044→        }
  1045→
  1046→        stringBuilder
  1047→            .AppendLine()
  1048→            .Append(entityTypeBuilderName)
  1049→            .Append(".ToTable(");
  1050→
  1051→        if (explicitName)
  1052→        {
  1053→            if (tableName == null
  1054→                && (schemaAnnotation == null || schema == null))
  1055→            {
  1056→                stringBuilder.Append("(string)");
  1057→            }
  1058→
  1059→            stringBuilder.Append(Code.Literal(tableName));
  1060→
  1061→            if (isExcludedAnnotation is not null)
  1062→            {
  1063→                annotations.Remove(isExcludedAnnotation.Name);
  1064→            }
  1065→
  1066→            if (schema != null
  1067→                || (schemaAnnotation != null && tableName != null))
  1068→            {
  1069→                stringBuilder
  1070→                    .Append(", ");
  1071→
  1072→                if (schema == null && !requiresTableBuilder)
  1073→                {
  1074→                    stringBuilder.Append("(string)");
  1075→                }
  1076→
  1077→                stringBuilder.Append(Code.Literal(schema));
  1078→            }
  1079→        }
  1080→
  1081→        if (requiresTableBuilder)
  1082→        {
  1083→            using (stringBuilder.Indent())
  1084→            {
  1085→                if (explicitName)
  1086→                {
  1087→                    stringBuilder.Append(", ");
  1088→                }
  1089→
  1090→                stringBuilder
  1091→                    .AppendLine("t =>")
  1092→                    .Append("{");
  1093→
