  1166→    private void GenerateViewMapping(
  1167→        string entityTypeBuilderName,
  1168→        IEntityType entityType,
  1169→        IndentedStringBuilder stringBuilder,
  1170→        Dictionary<string, IAnnotation> annotations)
  1171→    {
  1172→        annotations.TryGetAndRemove(RelationalAnnotationNames.ViewName, out IAnnotation? viewNameAnnotation);
  1173→        annotations.TryGetAndRemove(RelationalAnnotationNames.ViewSchema, out IAnnotation? viewSchemaAnnotation);
  1174→        annotations.Remove(RelationalAnnotationNames.ViewDefinitionSql);
  1175→
  1176→        var view = StoreObjectIdentifier.Create(entityType, StoreObjectType.View);
  1177→        var viewName = (string?)viewNameAnnotation?.Value ?? view?.Name;
  1178→        if (viewNameAnnotation == null
  1179→            && (viewName == null || entityType.BaseType?.GetViewName() == viewName))
  1180→        {
  1181→            return;
  1182→        }
  1183→
  1184→        stringBuilder
  1185→            .AppendLine()
  1186→            .Append(entityTypeBuilderName)
  1187→            .Append(".ToView(")
  1188→            .Append(Code.Literal(viewName));
  1189→        if (viewNameAnnotation != null)
  1190→        {
  1191→            annotations.Remove(viewNameAnnotation.Name);
  1192→        }
  1193→
  1194→        var hasOverrides = view != null
  1195→            && entityType.GetProperties().Select(p => p.FindOverrides(view.Value)).Any(o => o != null);
  1196→
  1197→        var schema = (string?)viewSchemaAnnotation?.Value ?? view?.Schema;
  1198→        if (schema != null
  1199→            || viewSchemaAnnotation != null)
  1200→        {
  1201→            stringBuilder
  1202→                .Append(", ");
  1203→
  1204→            if (schema == null && !hasOverrides)
  1205→            {
  1206→                stringBuilder.Append("(string)");
  1207→            }
  1208→
  1209→            stringBuilder.Append(Code.Literal(schema));
  1210→        }
  1211→
  1212→        if (hasOverrides)
  1213→        {
  1214→            stringBuilder.AppendLine(", v =>");
  1215→
  1216→            using (stringBuilder.Indent())
  1217→            {
  1218→                stringBuilder.Append("{");
  1219→
  1220→                using (stringBuilder.Indent())
  1221→                {
  1222→                    GeneratePropertyOverrides("v", entityType, view!.Value, stringBuilder);
  1223→                }
  1224→
  1225→                stringBuilder.Append("}");
  1226→            }
  1227→        }
  1228→
  1229→        stringBuilder.AppendLine(");");
  1230→    }
