  1543→    /// <param name="stringBuilder">The builder code is added to.</param>
  1544→    protected virtual void GenerateForeignKey(
  1545→        string entityTypeBuilderName,
  1546→        IForeignKey foreignKey,
  1547→        IndentedStringBuilder stringBuilder)
  1548→    {
  1549→        var foreignKeyBuilderNameStringBuilder = new StringBuilder();
  1550→
  1551→        if (!foreignKey.IsOwnership)
  1552→        {
  1553→            foreignKeyBuilderNameStringBuilder
  1554→                .Append(entityTypeBuilderName)
  1555→                .Append(".HasOne(")
  1556→                .Append(Code.Literal(GetFullName(foreignKey.PrincipalEntityType)))
  1557→                .Append(", ")
  1558→                .Append(Code.Literal(foreignKey.DependentToPrincipal?.Name));
  1559→        }
  1560→        else
  1561→        {
  1562→            foreignKeyBuilderNameStringBuilder
  1563→                .Append(entityTypeBuilderName)
  1564→                .Append(".WithOwner(");
  1565→
  1566→            if (foreignKey.DependentToPrincipal != null)
  1567→            {
  1568→                foreignKeyBuilderNameStringBuilder
  1569→                    .Append(Code.Literal(foreignKey.DependentToPrincipal.Name));
  1570→            }
  1571→        }
  1572→
  1573→        foreignKeyBuilderNameStringBuilder.Append(')');
  1574→
  1575→        var foreignKeyBuilderName = foreignKeyBuilderNameStringBuilder.ToString();
  1576→
  1577→        stringBuilder
  1578→            .Append(foreignKeyBuilderName)
  1579→            .AppendLine();
  1580→
  1581→        // Note that GenerateAnnotations below does the corresponding decrement
  1582→        stringBuilder.IncrementIndent();
  1583→
  1584→        if (foreignKey.IsUnique
  1585→            && !foreignKey.IsOwnership)
  1586→        {
  1587→            stringBuilder
  1588→                .Append(".WithOne(");
  1589→
  1590→            if (foreignKey.PrincipalToDependent != null)
  1591→            {
  1592→                stringBuilder
  1593→                    .Append(Code.Literal(foreignKey.PrincipalToDependent.Name));
  1594→            }
  1595→
  1596→            stringBuilder
  1597→                .AppendLine(")")
  1598→                .Append(".HasForeignKey(")
  1599→                .Append(Code.Literal(GetFullName(foreignKey.DeclaringEntityType)))
  1600→                .Append(", ")
  1601→                .Append(string.Join(", ", foreignKey.Properties.Select(p => Code.Literal(p.Name))))
  1602→                .Append(")");
  1603→
  1604→            if (foreignKey.PrincipalKey != foreignKey.PrincipalEntityType.FindPrimaryKey())
  1605→            {
  1606→                stringBuilder
  1607→                    .AppendLine()
  1608→                    .Append(".HasPrincipalKey(")
  1609→                    .Append(Code.Literal(GetFullName(foreignKey.PrincipalEntityType)))
  1610→                    .Append(", ")
  1611→                    .Append(string.Join(", ", foreignKey.PrincipalKey.Properties.Select(p => Code.Literal(p.Name))))
  1612→                    .Append(")");
  1613→            }
  1614→        }
  1615→        else
  1616→        {
  1617→            if (!foreignKey.IsOwnership)
  1618→            {
  1619→                stringBuilder
  1620→                    .Append(".WithMany(");
  1621→
  1622→                if (foreignKey.PrincipalToDependent != null)
  1623→                {
  1624→                    stringBuilder
  1625→                        .Append(Code.Literal(foreignKey.PrincipalToDependent.Name));
  1626→                }
  1627→
  1628→                stringBuilder
  1629→                    .AppendLine(")");
  1630→            }
  1631→
  1632→            stringBuilder
  1633→                .Append(".HasForeignKey(")
  1634→                .Append(string.Join(", ", foreignKey.Properties.Select(p => Code.Literal(p.Name))))
  1635→                .Append(")");
  1636→
  1637→            if (foreignKey.PrincipalKey != foreignKey.PrincipalEntityType.FindPrimaryKey())
  1638→            {
  1639→                stringBuilder
  1640→                    .AppendLine()
  1641→                    .Append(".HasPrincipalKey(")
  1642→                    .Append(string.Join(", ", foreignKey.PrincipalKey.Properties.Select(p => Code.Literal(p.Name))))
  1643→                    .Append(")");
  1644→            }
  1645→        }
  1646→
  1647→        if (!foreignKey.IsOwnership)
  1648→        {
  1649→            if (foreignKey.DeleteBehavior != DeleteBehavior.ClientSetNull)
  1650→            {
  1651→                stringBuilder
  1652→                    .AppendLine()
  1653→                    .Append(".OnDelete(")
  1654→                    .Append(Code.Literal(foreignKey.DeleteBehavior))
  1655→                    .Append(")");
  1656→            }
  1657→
  1658→            if (foreignKey.IsRequired)
  1659→            {
  1660→                stringBuilder
  1661→                    .AppendLine()
  1662→                    .Append(".IsRequired()");
  1663→            }
  1664→        }
  1665→
  1666→        GenerateForeignKeyAnnotations(foreignKeyBuilderName, foreignKey, stringBuilder);
  1667→    }
