  1690→    /// <param name="modelBuilderName">The name of the builder variable.</param>
  1691→    /// <param name="entityType">The entity type.</param>
  1692→    /// <param name="stringBuilder">The builder code is added to.</param>
  1693→    protected virtual void GenerateEntityTypeNavigations(
  1694→        string modelBuilderName,
  1695→        IEntityType entityType,
  1696→        IndentedStringBuilder stringBuilder)
  1697→    {
  1698→        stringBuilder
  1699→            .Append(modelBuilderName)
  1700→            .Append(".Entity(")
  1701→            .Append(Code.Literal(entityType.Name))
  1702→            .AppendLine(", b =>");
  1703→
  1704→        using (stringBuilder.Indent())
  1705→        {
  1706→            stringBuilder.Append("{");
  1707→
  1708→            using (stringBuilder.Indent())
  1709→            {
  1710→                GenerateNavigations(
  1711→                    "b", entityType.GetDeclaredNavigations()
  1712→                        .Where(n => !n.IsOnDependent && !n.ForeignKey.IsOwnership), stringBuilder);
  1713→            }
  1714→
  1715→            stringBuilder.AppendLine("});");
  1716→        }
  1717→    }
  1718→
  1719→    /// <summary>
  1720→    ///     Generates code for <see cref="INavigation" /> objects.
  1721→    /// </summary>
  1722→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
  1723→    /// <param name="navigations">The navigations.</param>
  1724→    /// <param name="stringBuilder">The builder code is added to.</param>
  1725→    protected virtual void GenerateNavigations(
  1726→        string entityTypeBuilderName,
  1727→        IEnumerable<INavigation> navigations,
  1728→        IndentedStringBuilder stringBuilder)
  1729→    {
  1730→        foreach (var navigation in navigations)
  1731→        {
  1732→            stringBuilder.AppendLine();
  1733→
  1734→            GenerateNavigation(entityTypeBuilderName, navigation, stringBuilder);
  1735→        }
  1736→    }
  1737→
  1738→    /// <summary>
  1739→    ///     Generates code for an <see cref="INavigation" />.
  1740→    /// </summary>
  1741→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
  1742→    /// <param name="navigation">The navigation.</param>
  1743→    /// <param name="stringBuilder">The builder code is added to.</param>
  1744→    protected virtual void GenerateNavigation(
  1745→        string entityTypeBuilderName,
  1746→        INavigation navigation,
  1747→        IndentedStringBuilder stringBuilder)
  1748→    {
  1749→        var navigationBuilderName = $"{entityTypeBuilderName}.Navigation({Code.Literal(navigation.Name)})";
  1750→
  1751→        stringBuilder.Append(navigationBuilderName);
  1752→
  1753→        // Note that GenerateAnnotations below does the corresponding decrement
  1754→        stringBuilder.IncrementIndent();
  1755→
  1756→        if (!navigation.IsOnDependent
  1757→            && !navigation.IsCollection
  1758→            && navigation.ForeignKey.IsRequiredDependent)
  1759→        {
  1760→            stringBuilder
  1761→                .AppendLine()
  1762→                .Append(".IsRequired()");
  1763→        }
  1764→
  1765→        GenerateNavigationAnnotations(navigationBuilderName, navigation, stringBuilder);
  1766→    }
  1767→
  1768→    /// <summary>
  1769→    ///     Generates code for the annotations on a navigation.
  1770→    /// </summary>
  1771→    /// <param name="navigationBuilderName">The name of the builder variable.</param>
  1772→    /// <param name="navigation">The navigation.</param>
  1773→    /// <param name="stringBuilder">The builder code is added to.</param>
  1774→    protected virtual void GenerateNavigationAnnotations(
  1775→        string navigationBuilderName,
  1776→        INavigation navigation,
  1777→        IndentedStringBuilder stringBuilder)
  1778→    {
  1779→        var annotations = Dependencies.AnnotationCodeGenerator
  1780→            .FilterIgnoredAnnotations(navigation.GetAnnotations())
  1781→            .ToDictionary(a => a.Name, a => a);
  1782→
  1783→        GenerateAnnotations(navigationBuilderName, navigation, stringBuilder, annotations, inChainedCall: true);
  1784→    }
  1785→
  1786→    /// <summary>
  1787→    ///     Generates code for data seeding.
  1788→    /// </summary>
  1789→    /// <param name="entityTypeBuilderName">The name of the builder variable.</param>
  1790→    /// <param name="properties">The properties to generate.</param>
  1791→    /// <param name="data">The data to be seeded.</param>
  1792→    /// <param name="stringBuilder">The builder code is added to.</param>
  1793→    protected virtual void GenerateData(
  1794→        string entityTypeBuilderName,
  1795→        IEnumerable<IProperty> properties,
  1796→        IEnumerable<IDictionary<string, object?>> data,
  1797→        IndentedStringBuilder stringBuilder)
  1798→    {
  1799→        var dataList = data.ToList();
  1800→        if (dataList.Count == 0)
  1801→        {
  1802→            return;
  1803→        }
  1804→
  1805→        var propertiesToOutput = properties.ToList();
  1806→
  1807→        stringBuilder
  1808→            .AppendLine()
  1809→            .Append(entityTypeBuilderName)
  1810→            .Append(".")
  1811→            .Append(nameof(EntityTypeBuilder.HasData))
  1812→            .AppendLine("(");
  1813→
  1814→        using (stringBuilder.Indent())
  1815→        {
  1816→            var firstDatum = true;
  1817→            foreach (var o in dataList)
  1818→            {
  1819→                if (!firstDatum)
  1820→                {
  1821→                    stringBuilder.AppendLine(",");
  1822→                }
  1823→                else
  1824→                {
  1825→                    firstDatum = false;
  1826→                }
  1827→
  1828→                stringBuilder
  1829→                    .AppendLine("new")
  1830→                    .AppendLine("{");
  1831→
  1832→                using (stringBuilder.Indent())
  1833→                {
  1834→                    var firstProperty = true;
  1835→                    foreach (var property in propertiesToOutput)
  1836→                    {
  1837→                        if (o.TryGetValue(property.Name, out var value)
  1838→                            && value != null)
  1839→                        {
  1840→                            if (!firstProperty)
  1841→                            {
  1842→                                stringBuilder.AppendLine(",");
  1843→                            }
  1844→                            else
  1845→                            {
  1846→                                firstProperty = false;
  1847→                            }
  1848→
  1849→                            stringBuilder
  1850→                                .Append(Code.Identifier(property.Name))
  1851→                                .Append(" = ")
  1852→                                .Append(Code.UnknownLiteral(value));
  1853→                        }
  1854→                    }
  1855→
  1856→                    stringBuilder.AppendLine();
  1857→                }
  1858→
  1859→                stringBuilder.Append("}");
  1860→            }
  1861→        }
  1862→
  1863→        stringBuilder
  1864→            .AppendLine(");");
  1865→    }
  1866→
  1867→    private void GenerateFluentApiForMaxLength(
  1868→        IProperty property,
  1869→        IndentedStringBuilder stringBuilder)
  1870→    {
  1871→        if (property.GetMaxLength() is { } maxLength)
  1872→        {
  1873→            stringBuilder
  1874→                .AppendLine()
  1875→                .Append(".")
  1876→                .Append(nameof(PropertyBuilder.HasMaxLength))
  1877→                .Append("(")
  1878→                .Append(Code.Literal(maxLength))
  1879→                .Append(")");
  1880→        }
  1881→    }
  1882→
  1883→    private void GenerateFluentApiForPrecisionAndScale(
  1884→        IProperty property,
  1885→        IndentedStringBuilder stringBuilder)
  1886→    {
  1887→        if (property.GetPrecision() is { } precision)
  1888→        {
  1889→            stringBuilder
  1890→                .AppendLine()
  1891→                .Append(".")
  1892→                .Append(nameof(PropertyBuilder.HasPrecision))
  1893→                .Append("(")
  1894→                .Append(Code.Literal(precision));
  1895→
  1896→            if (property.GetScale() is { } scale)
  1897→            {
  1898→                if (scale != 0)
  1899→                {
  1900→                    stringBuilder
  1901→                        .Append(", ")
  1902→                        .Append(Code.Literal(scale));
  1903→                }
  1904→            }
  1905→
  1906→            stringBuilder.Append(")");
  1907→        }
  1908→    }
  1909→
  1910→    private void GenerateFluentApiForIsUnicode(
  1911→        IProperty property,
  1912→        IndentedStringBuilder stringBuilder)
  1913→    {
  1914→        if (property.IsUnicode() is { } unicode)
  1915→        {
  1916→            stringBuilder
  1917→                .AppendLine()
  1918→                .Append(".")
  1919→                .Append(nameof(PropertyBuilder.IsUnicode))
  1920→                .Append("(")
  1921→                .Append(Code.Literal(unicode))
  1922→                .Append(")");
  1923→        }
  1924→    }
  1925→
  1926→    private void GenerateAnnotations(
  1927→        string builderName,
  1928→        IAnnotatable annotatable,
  1929→        IndentedStringBuilder stringBuilder,
  1930→        Dictionary<string, IAnnotation> annotations,
  1931→        bool inChainedCall,
  1932→        bool leadingNewline = true,
  1933→        MethodInfo? hasAnnotationMethodInfo = null)
  1934→    {
  1935→        var fluentApiCalls = Dependencies.AnnotationCodeGenerator.GenerateFluentApiCalls(annotatable, annotations);
  1936→
  1937→        MethodCallCodeFragment? chainedCall = null;
  1938→        var typeQualifiedCalls = new List<MethodCallCodeFragment>();
  1939→
  1940→        // Chain together all Fluent API calls which we can, and leave the others to be generated as type-qualified
  1941→        foreach (var call in fluentApiCalls)
  1942→        {
  1943→            if (call.MethodInfo is not null
  1944→                && call.MethodInfo.IsStatic
  1945→                && (call.MethodInfo.DeclaringType is null
  1946→                    || call.MethodInfo.DeclaringType.Assembly != typeof(RelationalModelBuilderExtensions).Assembly))
  1947→            {
  1948→                typeQualifiedCalls.Add(call);
  1949→            }
  1950→            else
  1951→            {
  1952→                chainedCall = chainedCall is null ? call : chainedCall.Chain(call);
  1953→            }
  1954→        }
  1955→
  1956→        // Append remaining raw annotations which did not get generated as Fluent API calls
  1957→        foreach (var annotation in annotations.Values.OrderBy(a => a.Name))
  1958→        {
  1959→            var call = new MethodCallCodeFragment(
  1960→                hasAnnotationMethodInfo ?? HasAnnotationMethodInfo,
  1961→                annotation.Name, annotation.Value);
  1962→            chainedCall = chainedCall is null ? call : chainedCall.Chain(call);
  1963→        }
  1964→
  1965→        // First generate single Fluent API call chain
  1966→        if (chainedCall is not null)
  1967→        {
  1968→            if (inChainedCall)
  1969→            {
  1970→                if (chainedCall.ChainedCall is null)
  1971→                {
  1972→                    stringBuilder.AppendLine();
  1973→                }
  1974→
  1975→                stringBuilder.Append(Code.Fragment(chainedCall, stringBuilder.IndentCount));
  1976→            }
  1977→            else
  1978→            {
  1979→                if (leadingNewline)
  1980→                {
  1981→                    stringBuilder.AppendLine();
  1982→                }
  1983→
  1984→                stringBuilder.Append(builderName);
  1985→                stringBuilder.Append(Code.Fragment(chainedCall, stringBuilder.IndentCount + 1));
  1986→                stringBuilder.AppendLine(";");
  1987→            }
  1988→
  1989→            leadingNewline = true;
  1990→        }
  1991→
  1992→        if (inChainedCall)
  1993→        {
  1994→            stringBuilder.AppendLine(";");
  1995→            stringBuilder.DecrementIndent();
  1996→        }
  1997→
  1998→        // Then generate separate fully-qualified calls
  1999→        if (typeQualifiedCalls.Count > 0)
  2000→        {
  2001→            if (leadingNewline)
  2002→            {
  2003→                stringBuilder.AppendLine();
  2004→            }
  2005→
  2006→            foreach (var call in typeQualifiedCalls)
  2007→            {
  2008→                stringBuilder.Append(Code.Fragment(call, builderName, typeQualified: true));
  2009→                stringBuilder.AppendLine(";");
  2010→            }
  2011→        }
  2012→    }
  2013→
  2014→    private static string GetFullName(IReadOnlyEntityType entityType)
  2015→    {
  2016→        var entityTypeName = entityType.Name;
  2017→        var ownership = entityType.FindOwnership();
  2018→        if (ownership == null)
  2019→        {
  2020→            return entityTypeName;
  2021→        }
  2022→
  2023→        if (entityType.HasSharedClrType
  2024→            && entityTypeName
  2025→            == ownership.PrincipalEntityType.GetOwnedName(
  2026→                entityType.ClrType.ShortDisplayName(), ownership.PrincipalToDependent!.Name))
  2027→        {
  2028→            entityTypeName = entityType.ClrType.DisplayName();
  2029→        }
  2030→
  2031→        return GetFullName(ownership.PrincipalEntityType)
  2032→            + "."
  2033→            + ownership.PrincipalToDependent!.Name
  2034→            + "#"
  2035→            + entityTypeName;
  2036→    }
  2037→}
