using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Design;
using Microsoft.EntityFrameworkCore.Design.Internal;
using Microsoft.EntityFrameworkCore.Infrastructure;
using Microsoft.EntityFrameworkCore.Metadata;
using Microsoft.EntityFrameworkCore.Migrations.Design;
using Microsoft.EntityFrameworkCore.SqlServer.Design.Internal;
using Microsoft.EntityFrameworkCore.SqlServer.Infrastructure.Internal;
using Microsoft.EntityFrameworkCore.SqlServer.Storage.Internal;
using Microsoft.EntityFrameworkCore.Storage;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ComplexCollectionTest
{
    public class Person
    {
        public Guid Id { get; set; }
        public string Name { get; set; } = null!;
        public PersonDetails Details { get; set; }
    }

    public struct PersonDetails
    {
        public List<Address> Addresses { get; set; }
        public List<Phone> Phones { get; set; }
    }

    public class Address
    {
        public string City { get; set; } = null!;
        public string State { get; set; } = null!;
        public string Street { get; set; } = null!;
        public string ZipCode { get; set; } = null!;
    }

    public class Phone
    {
        public string Number { get; set; } = null!;
        public PhoneType Type { get; set; } = PhoneType.Mobile;
    }

    public enum PhoneType
    {
        Mobile,
        Home,
        Work,
        Other
    }

    class Program
    {
        static void Main(string[] args)
        {
            Console.WriteLine("Testing Complex Collection Type Bug...\n");

            // Create model builder
            var modelBuilder = new ModelBuilder();

            modelBuilder.Entity<Person>(b =>
            {
                b.Property(p => p.Id);
                b.Property(p => p.Name).IsRequired();
                b.HasKey(p => p.Id);
                b.ToTable("Persons");

                b.ComplexProperty(p => p.Details, pb =>
                {
                    pb.ComplexProperty(d => d.Addresses);
                    pb.ComplexProperty(d => d.Phones);
                    pb.ToJson();
                });
            });

            var model = modelBuilder.FinalizeModel(designTime: true);

            // Create generator
            var sqlServerTypeMappingSource = new SqlServerTypeMappingSource(
                new TypeMappingSourceDependencies(
                    new ValueConverterSelector(new ValueConverterSelectorDependencies()),
                    Array.Empty<ITypeMappingSourcePlugin>()),
                new RelationalTypeMappingSourceDependencies(
                    Array.Empty<IRelationalTypeMappingSourcePlugin>()),
                new SqlServerSingletonOptions());

            var codeHelper = new CSharpHelper(sqlServerTypeMappingSource);

            var sqlServerAnnotationCodeGenerator = new SqlServerAnnotationCodeGenerator(
                new AnnotationCodeGeneratorDependencies(sqlServerTypeMappingSource));

            var generator = new CSharpSnapshotGenerator(
                new CSharpSnapshotGeneratorDependencies(
                    codeHelper, sqlServerTypeMappingSource, sqlServerAnnotationCodeGenerator));

            var sb = new IndentedStringBuilder();
            generator.Generate("modelBuilder", model, sb);

            var result = sb.ToString();
            Console.WriteLine("Generated Snapshot:");
            Console.WriteLine("==================");
            Console.WriteLine(result);
            Console.WriteLine("==================\n");

            // Check for the bug
            bool hasDictionaryBug = result.Contains("typeof(Dictionary<string, object>)");
            bool hasCorrectType = result.Contains("typeof(List<") || result.Contains("typeof(System.Collections.Generic.List<");

            if (hasDictionaryBug && !hasCorrectType)
            {
                Console.WriteLine("❌ BUG FOUND: Complex collections are scaffolded with Dictionary<string, object> instead of the actual type");

                // Show what the actual types should be
                var entityType = model.FindEntityType(typeof(Person));
                var complexProperty = entityType.GetComplexProperties().First();
                var complexType = complexProperty.ComplexType;

                Console.WriteLine("\nExpected types:");
                foreach (var nestedComplexProperty in complexType.GetComplexProperties())
                {
                    Console.WriteLine($"  Property: {nestedComplexProperty.Name}, ClrType: {nestedComplexProperty.ClrType.Name}, IsCollection: {nestedComplexProperty.IsCollection}");
                }

                Environment.Exit(1);
            }
            else if (!hasDictionaryBug && hasCorrectType)
            {
                Console.WriteLine("✅ Bug is FIXED: Complex collections are scaffolded with the correct type");
                Environment.Exit(0);
            }
            else
            {
                Console.WriteLine($"⚠️ Unexpected result - hasDictionaryBug: {hasDictionaryBug}, hasCorrectType: {hasCorrectType}");
                Environment.Exit(2);
            }
        }
    }
}

