                    b.Property<Guid>("Property")
                        .HasColumnType("uniqueidentifier");

                    b.HasKey("Id");

                    b.HasIndex("Property");

                    b.ToTable("EntityWithGenericProperty<Guid>", "DefaultSchema");
                });

